"use strict";exports.formatDate=function(t,r="YYYY-MM-DD HH:mm:ss"){if(!t)return"";const a=new Date(t),e=a.getFullYear(),n=String(a.getMonth()+1).padStart(2,"0"),o=String(a.getDate()).padStart(2,"0"),i=String(a.getHours()).padStart(2,"0"),S=String(a.getMinutes()).padStart(2,"0"),p=String(a.getSeconds()).padStart(2,"0");return r.replace("YYYY",e).replace("MM",n).replace("DD",o).replace("HH",i).replace("mm",S).replace("ss",p)},exports.formatDistance=function(t){return t?t<1e3?`${t}m`:`${(t/1e3).toFixed(2)}km`:"0km"},exports.formatDuration=function(t){if(!t)return"00:00:00";const r=Math.floor(t/3600),a=Math.floor(t%3600/60),e=t%60;return r>0?`${String(r).padStart(2,"0")}:${String(a).padStart(2,"0")}:${String(e).padStart(2,"0")}`:`${String(a).padStart(2,"0")}:${String(e).padStart(2,"0")}`},exports.formatPace=function(t){if(!t||0===t)return"0'00\"";const r=Math.floor(t/60),a=Math.floor(t%60);return`${r}'${String(a).padStart(2,"0")}"`};
